<?php
$inversion=0;$valorVenta=0;foreach($productos as $p){$inversion+=(float)($p['precio_costo']??0);$valorVenta+=(float)($p['precio_final']??$p['precio_venta']??$p['precio']??0);} $ingresos=0;$ventasCount=0;$porMes=[];foreach($ventas as $v){$total=(float)($v['total']??0);$ingresos+=$total;$ventasCount++;$mes=substr((string)($v['fecha']??$v['created_at']??date('Y-m')),0,7);$porMes[$mes]=($porMes[$mes]??0)+$total;}foreach($manuales as $m){$total=(float)($m['total']??0);$ingresos+=$total;$ventasCount++;$mes=substr((string)($m['fecha']??$m['created_at']??date('Y-m')),0,7);$porMes[$mes]=($porMes[$mes]??0)+$total;}foreach(($pedidos??[]) as $p){if(($p['estado']??'')==='vendido'){$total=(float)($p['vendido_total']??$p['vendido_precio_final']??$p['producto_precio']??0);$ingresos+=$total;$ventasCount++;$mes=substr((string)($p['vendido_at']??$p['created_at']??date('Y-m')),0,7);$porMes[$mes]=($porMes[$mes]??0)+$total;}}ksort($porMes);$recuperado=min($ingresos,$inversion);$activa=max(0,$inversion-$recuperado);$ganancia=$ingresos-$inversion;$cajaTotal=$ingresos;$cajaLibre=max(0,$ingresos-$activa);$ticket=$ventasCount?($ingresos/$ventasCount):0;$maxMes=max($porMes?:[1]);?>
<section class="page-head"><div><h1>Contabilidad</h1><p>Inversión, recuperación, ingresos, ganancia real y caja disponible.</p></div></section>
<div class="kpi-grid"><div class="kpi"><span>Inversión total</span><strong><?= money_ar($inversion) ?></strong></div><div class="kpi"><span>Inversión recuperada</span><strong><?= money_ar($recuperado) ?></strong></div><div class="kpi"><span>Inversión activa</span><strong><?= money_ar($activa) ?></strong></div><div class="kpi"><span>Ingresos</span><strong><?= money_ar($ingresos) ?></strong></div><div class="kpi"><span>Ganancia real</span><strong><?= money_ar($ganancia) ?></strong></div><div class="kpi"><span>Caja total</span><strong><?= money_ar($cajaTotal) ?></strong></div><div class="kpi"><span>Caja libre</span><strong><?= money_ar($cajaLibre) ?></strong></div><div class="kpi"><span>Ticket promedio</span><strong><?= money_ar($ticket) ?></strong></div></div>
<?php if(!$ventasCount): ?><div class="empty-state">Todavía no hay ventas registradas. Cuando existan ventas se mostrarán ingresos por mes y recuperación.</div><?php else: ?><div class="chart-panel"><div class="panel"><h2>Inversión recuperada vs pendiente</h2><div class="stat-list"><div class="stat-line"><span>Recuperada</span><strong><?= money_ar($recuperado) ?></strong></div><div class="stat-line"><span>Pendiente</span><strong><?= money_ar($activa) ?></strong></div><div class="stat-line"><span>Ganancia</span><strong><?= money_ar($ganancia) ?></strong></div></div></div><div class="panel"><h2>Operaciones</h2><div class="stat-list"><div class="stat-line"><span>Ventas registradas</span><strong><?= $ventasCount ?></strong></div><div class="stat-line"><span>Ticket promedio</span><strong><?= money_ar($ticket) ?></strong></div><div class="stat-line"><span>Valor de venta cargado</span><strong><?= money_ar($valorVenta) ?></strong></div></div></div></div><div class="panel"><h2>Ingresos por mes</h2><?php foreach($porMes as $mes=>$total): ?><div class="stat-line"><span><?= e($mes) ?></span><strong><?= money_ar($total) ?></strong></div><?php endforeach; ?></div><?php endif; ?>
